svg.script:
const ring = document.getElementById("rainbowRing");
const visibleBias = document.getElementById("visibleBias");
const halo = document.getElementById("halo");
const runnerAura = document.getElementById("runnerAura");
const runnerTail = document.getElementById("runnerTail");
const runnerCore = document.getElementById("runnerCore");
const ringLayers = [
  { el: document.getElementById("r1"), opacity: .74 },
  { el: document.getElementById("r2"), opacity: .68 },
  { el: document.getElementById("r3"), opacity: .58 },
  { el: document.getElementById("r4"), opacity: .48 },
];
const cloudWrap = document.getElementById("cloudWrap");
const capsule = document.getElementById("capsuleEye");
const arcEye = document.getElementById("arcEye");
const arcL = document.getElementById("arcL");
const arcR = document.getElementById("arcR");
const sparkEls = [...document.querySelectorAll(".spark")];
const phaseReadout = document.getElementById("phase-readout");
const timeReadout = document.getElementById("time-readout");

const SWEEP_OFFSET = -16;
const RING_COUNT = 4;
const SMILE = { h: .72, w: 2.65 };
const LAUGH = { h: 1.02, w: 3.05 };
const EYE_CY = 12.62;
const CX_L = 7.75;
const CX_R = 12.15;
const sparks = [
  { x: 3.2, y: 6.3, dx: -2.15, dy: -1.45, d: 0.00, s: 1.10, rot: -18, alpha: 1.00 },
  { x: 1.9, y: 14.6, dx: -2.10, dy: .95, d: .14, s: .98, rot: -28, alpha: .96 },
  { x: 8.6, y: 21.2, dx: -.8, dy: 1.95, d: .24, s: .86, rot: 12, alpha: .88 },
  { x: 20.4, y: 6.2, dx: 2.05, dy: -1.35, d: .08, s: .88, rot: 24, alpha: .80 },
  { x: 22.1, y: 15.0, dx: 2.05, dy: 1.25, d: .20, s: .82, rot: -14, alpha: .76 },
  { x: 13.8, y: 2.0, dx: .45, dy: -2.10, d: .30, s: .80, rot: 16, alpha: .72 },
];
const params = {
  duration: 3.6,
  ringPower: 1.25,
  edgeBias: .30,
  bounce: .040,
};
let startT = performance.now();
let paused = false;
let heldT = 0;
let lastRender = null;

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }
function lerp(a, b, t) { return a + (b - a) * t; }
function easeOutCubic(x) { return 1 - Math.pow(1 - x, 3); }
function easeInCubic(x) { return x * x * x; }
function easeInOutCubic(x) {
  return x < .5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2;
}
function arcPath(shape) {
  const w2 = shape.w / 2;
  const peakY = EYE_CY - 2 * shape.h;
  return {
    l: `M ${(CX_L - w2).toFixed(2)} ${EYE_CY} Q ${CX_L} ${peakY.toFixed(2)} ${(CX_L + w2).toFixed(2)} ${EYE_CY}`,
    r: `M ${(CX_R - w2).toFixed(2)} ${EYE_CY} Q ${CX_R} ${peakY.toFixed(2)} ${(CX_R + w2).toFixed(2)} ${EYE_CY}`,
  };
}
function setArc(shape) {
  const d = arcPath(shape);
  arcL.setAttribute("d", d.l);
  arcR.setAttribute("d", d.r);
}
function setCenteredTransform(el, sx, sy = sx, rot = 0, tx = 0, ty = 0) {
  el.setAttribute("transform", `translate(${(12 + tx).toFixed(3)} ${(12 + ty).toFixed(3)}) rotate(${rot.toFixed(3)}) scale(${sx.toFixed(4)} ${sy.toFixed(4)}) translate(-12 -12)`);
}
function setRing(layerLevels, haloOpacity, scale, runnerProgress, runnerOpacity, edgeBoost) {
  ringLayers.forEach(({ el, opacity }, i) => {
    el.setAttribute("stroke-dasharray", "100 .01");
    el.setAttribute("stroke-dashoffset", 0);
    el.setAttribute("stroke-opacity", (clamp(layerLevels[i] || 0, 0, 1) * opacity * params.ringPower).toFixed(3));
  });
  halo.setAttribute("stroke-dasharray", "100 .01");
  halo.setAttribute("stroke-dashoffset", 0);
  halo.setAttribute("stroke-opacity", clamp(haloOpacity * params.ringPower, 0, .08).toFixed(3));
  visibleBias.setAttribute("stroke-opacity", clamp(edgeBoost * params.edgeBias, 0, .35).toFixed(3));
  const runnerOffset = SWEEP_OFFSET - 100 * runnerProgress;
  runnerAura.setAttribute("stroke-dashoffset", runnerOffset.toFixed(2));
  runnerTail.setAttribute("stroke-dashoffset", runnerOffset.toFixed(2));
  runnerCore.setAttribute("stroke-dashoffset", runnerOffset.toFixed(2));
  runnerAura.setAttribute("stroke-opacity", (runnerOpacity * .12 * params.ringPower).toFixed(3));
  runnerTail.setAttribute("stroke-opacity", (runnerOpacity * .56 * params.ringPower).toFixed(3));
  runnerCore.setAttribute("stroke-opacity", (runnerOpacity * .88 * params.ringPower).toFixed(3));
  setCenteredTransform(ring, scale);
}
function setSparkles(amount) {
  sparkEls.forEach((el, i) => {
    const cfg = sparks[i];
    const p = clamp((amount - cfg.d) / .92, 0, 1);
    const visible = Math.sin(Math.PI * p);
    const move = easeOutCubic(p);
    const x = cfg.x + cfg.dx * move;
    const y = cfg.y + cfg.dy * move;
    const scale = cfg.s * (.52 + .86 * visible);
    el.setAttribute("transform", `translate(${x.toFixed(2)} ${y.toFixed(2)}) rotate(${(cfg.rot + 70 * p).toFixed(1)}) scale(${scale.toFixed(3)})`);
    el.setAttribute("opacity", (visible * cfg.alpha).toFixed(3));
  });
}
function render(t) {
  const total = params.duration;
  const unit = total / 3.6;
  const T_charge = .20 * unit;
  const T_layers = 1.04 * unit;
  const T_confirm = .18 * unit;
  const T_hold = 1.38 * unit;
  const T_fade = .54 * unit;
  const T_back = .26 * unit;
  const a1 = T_charge;
  const a2 = a1 + T_layers;
  const a3 = a2 + T_confirm;
  const a4 = a3 + T_hold;
  const a5 = a4 + T_fade;
  const a6 = a5 + T_back;

  let phase = "mini-idle baseline";
  let layerLevels = [0, 0, 0, 0];
  let haloOpacity = 0;
  let ringScale = 1;
  let runnerProgress = 0;
  let runnerOpacity = 0;
  let edgeBoost = 0;
  let cloudSx = 1;
  let cloudSy = 1;
  let cloudRot = 0;
  let capsuleOp = 1;
  let arcOp = 0;
  let eye = SMILE;
  let sparkleAmount = 0;

  if (t < a1) {
    phase = "charge";
    const p = t / T_charge;
    const pulse = Math.sin(Math.PI * p);
    cloudSx = 1 + .04 * pulse;
    cloudSy = 1 - .055 * pulse;
  } else if (t < a2) {
    const p = (t - a1) / T_layers;
    const laps = p * RING_COUNT;
    const completed = Math.min(RING_COUNT, Math.floor(laps));
    const lapLocal = laps - completed;
    const lightIn = easeOutCubic(clamp(p * 4, 0, 1));
    const justLit = completed > 0 ? Math.max(0, 1 - (lapLocal * T_layers / RING_COUNT) / .09) : 0;
    phase = `runner ${Math.min(completed + 1, RING_COUNT)}/${RING_COUNT}`;
    layerLevels = ringLayers.map((_, i) => i < completed ? 1 : 0);
    ringScale = 1 + .010 * lightIn + .008 * justLit;
    runnerProgress = laps;
    runnerOpacity = .88 * lightIn;
    edgeBoost = .20 * lightIn + .30 * justLit;
    cloudSx = cloudSy = 1 + .010 * lightIn + params.bounce * .35 * justLit;
    capsuleOp = 1 - easeOutCubic(clamp(p * 1.55, 0, 1));
    arcOp = easeOutCubic(clamp(p * 1.55, 0, 1));
    eye = {
      h: lerp(SMILE.h, LAUGH.h, easeInOutCubic(clamp((p - .16) / .84, 0, 1))),
      w: lerp(SMILE.w, LAUGH.w, easeInOutCubic(clamp((p - .16) / .84, 0, 1))),
    };
  } else if (t < a3) {
    phase = "confirm pop";
    const p = (t - a2) / T_confirm;
    const pop = Math.sin(Math.PI * p);
    layerLevels = [1, 1, 1, 1];
    haloOpacity = .035;
    ringScale = 1.012 + .014 * pop;
    runnerProgress = RING_COUNT + p;
    runnerOpacity = .82 * (1 - .25 * p);
    edgeBoost = .42 + .20 * pop;
    cloudSx = cloudSy = 1.014 + params.bounce * pop;
    cloudRot = 1.8 * Math.sin(2 * Math.PI * p);
    capsuleOp = 0;
    arcOp = 1;
    eye = LAUGH;
    sparkleAmount = p * .72;
  } else if (t < a4) {
    phase = "happy hold";
    const p = (t - a3) / T_hold;
    layerLevels = [1, 1, 1, 1];
    haloOpacity = .032;
    ringScale = 1.020 + .004 * Math.sin(2 * Math.PI * p);
    edgeBoost = .42 + .08 * Math.sin(2 * Math.PI * p);
    cloudSx = cloudSy = 1.018 + .004 * Math.sin(2 * Math.PI * p);
    capsuleOp = 0;
    arcOp = 1;
    eye = LAUGH;
    sparkleAmount = .75 + p * .45;
  } else if (t < a5) {
    phase = "soft fade";
    const p = (t - a4) / T_fade;
    const keep = 1 - easeInCubic(p);
    layerLevels = [1, 1, 1, 1].map(() => .10 + .90 * keep);
    haloOpacity = .030 * keep;
    ringScale = 1.004 + .018 * keep;
    edgeBoost = .36 * keep;
    cloudSx = cloudSy = 1 + .018 * keep;
    capsuleOp = 0;
    arcOp = 1;
    eye = {
      h: lerp(LAUGH.h, SMILE.h, easeInOutCubic(p)),
      w: lerp(LAUGH.w, SMILE.w, easeInOutCubic(p)),
    };
    sparkleAmount = 1.2;
  } else if (t < a6) {
    phase = "return";
    const p = (t - a5) / T_back;
    const out = 1 - easeOutCubic(p);
    layerLevels = [1, 1, 1, 1].map(() => .10 * out);
    haloOpacity = .015 * out;
    ringScale = 1 + .015 * out;
    edgeBoost = .16 * out;
    capsuleOp = easeInOutCubic(p);
    arcOp = 1 - easeInOutCubic(p);
    eye = SMILE;
  }

  setCenteredTransform(cloudWrap, cloudSx, cloudSy, cloudRot);
  setRing(layerLevels, haloOpacity, ringScale, runnerProgress, runnerOpacity, edgeBoost);
  setSparkles(sparkleAmount);
  capsule.setAttribute("opacity", capsuleOp.toFixed(3));
  arcEye.setAttribute("opacity", arcOp.toFixed(3));
  setArc(eye);
  phaseReadout.textContent = `phase: ${phase}`;
  timeReadout.textContent = `time: ${clamp(t, 0, params.duration).toFixed(2)} / ${params.duration.toFixed(2)}`;
  lastRender = { t, phase, layerLevels, runnerOpacity, edgeBoost, capsuleOp, arcOp };
}
function tick(now) {
  if (!paused) {
    heldT = ((now - startT) / 1000) % (params.duration + .42);
    render(heldT > params.duration ? 0 : heldT);
  }
  requestAnimationFrame(tick);
}
function replay() {
  startT = performance.now();
  heldT = 0;
  paused = false;
  render(0);
}
requestAnimationFrame(tick);
